import{c as t,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Quản lý Nhân viên","description":"","frontmatter":{},"headers":[],"relativePath":"admin/quan-ly-nhan-vien.md","filePath":"admin/quan-ly-nhan-vien.md","lastUpdated":0}'),e={name:"admin/quan-ly-nhan-vien.md"};function o(d,n,c,r,l,s){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-nhan-vien" tabindex="-1">Quản lý Nhân viên <a class="header-anchor" href="#quan-ly-nhan-vien" aria-label="Permalink to “Quản lý Nhân viên”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/account/admin</code></p><p>Nhân viên là tài khoản nội bộ (kinh doanh, chăm sóc khách hàng, biên soạn nội dung, kế toán…) sử dụng khu vực <code>https://lamsonedutech.vn/admin/...</code> nhưng <strong>chỉ thấy những menu được Admin cho phép</strong>.</p><h2 id="danh-sach-nhan-vien" tabindex="-1">Danh sách nhân viên <a class="header-anchor" href="#danh-sach-nhan-vien" aria-label="Permalink to “Danh sách nhân viên”">​</a></h2><p>Cột thông tin:</p><ul><li>Họ tên, Ảnh đại diện</li><li>Số điện thoại, Email</li><li><strong>Chức vụ</strong> (gắn với một bộ quyền)</li><li>Phòng ban (nếu có)</li><li>Trạng thái</li><li>Thao tác</li></ul><h2 id="them-nhan-vien" tabindex="-1">Thêm nhân viên <a class="header-anchor" href="#them-nhan-vien" aria-label="Permalink to “Thêm nhân viên”">​</a></h2><ol><li>Bấm <strong>Thêm nhân viên</strong>.</li><li>Điền: Họ tên, Số điện thoại, Email, Mật khẩu mặc định.</li><li><strong>Chọn chức vụ</strong> từ danh sách (chức vụ phải tạo trước tại <a href="./phan-quyen">Phân quyền</a>).</li><li>(Tùy chọn) Phòng ban, ghi chú.</li><li>Bấm <strong>Lưu</strong>. Hệ thống gửi tài khoản cho nhân viên.</li></ol><h2 id="đoi-chuc-vu" tabindex="-1">Đổi chức vụ <a class="header-anchor" href="#đoi-chuc-vu" aria-label="Permalink to “Đổi chức vụ”">​</a></h2><ul><li>Bấm <strong>Sửa</strong> → chọn lại <strong>Chức vụ</strong>.</li><li>Nhân viên sẽ thấy menu Admin thay đổi ngay sau khi đăng nhập lại.</li></ul><h2 id="tam-khoa-xoa" tabindex="-1">Tạm khóa / Xóa <a class="header-anchor" href="#tam-khoa-xoa" aria-label="Permalink to “Tạm khóa / Xóa”">​</a></h2><ul><li>Khi nhân viên nghỉ việc: <strong>Khóa tài khoản ngay</strong> để cắt quyền truy cập.</li><li>Xóa tài khoản sau một khoảng thời gian (vd 30 ngày) để tránh mất lịch sử thao tác.</li></ul><h2 id="quy-trinh-cap-tai-khoan-nhan-vien-moi" tabindex="-1">Quy trình cấp tài khoản nhân viên mới <a class="header-anchor" href="#quy-trinh-cap-tai-khoan-nhan-vien-moi" aria-label="Permalink to “Quy trình cấp tài khoản nhân viên mới”">​</a></h2><ol><li>HR cung cấp thông tin nhân viên mới (vị trí, phòng ban).</li><li>Admin kiểm tra hoặc tạo <strong>chức vụ</strong> phù hợp ở <a href="./phan-quyen">Phân quyền</a> (ví dụ: &quot;Nhân viên CSKH&quot; - chỉ có quyền <code>student</code>, <code>comment</code>, <code>invoice</code>).</li><li>Admin tạo tài khoản nhân viên, gán chức vụ.</li><li>Gửi tài khoản, hướng dẫn đăng nhập, yêu cầu đổi mật khẩu lần đầu.</li><li>Theo dõi hoạt động qua <strong>Lịch sử thao tác</strong> (nếu có).</li></ol><h2 id="mot-so-chuc-vu-mau-nen-thiet-lap" tabindex="-1">Một số &quot;chức vụ&quot; mẫu nên thiết lập <a class="header-anchor" href="#mot-so-chuc-vu-mau-nen-thiet-lap" aria-label="Permalink to “Một số &quot;chức vụ&quot; mẫu nên thiết lập”">​</a></h2><table tabindex="0"><thead><tr><th>Chức vụ</th><th>Quyền nên bật</th></tr></thead><tbody><tr><td><strong>Quản trị cấp cao</strong></td><td>Tất cả</td></tr><tr><td><strong>Nhân viên kinh doanh</strong></td><td><code>student</code>, <code>invoice</code>, <code>discountCode</code>, <code>dealerDiscount</code>, <code>courseStudent</code></td></tr><tr><td><strong>Nhân viên CSKH / Hỗ trợ</strong></td><td><code>student</code>, <code>comment</code>, <code>invoice</code> (chỉ xem)</td></tr><tr><td><strong>Biên soạn nội dung</strong></td><td><code>course</code>, <code>modun</code>, <code>thematic</code>, <code>lesson</code>, <code>question</code>, <code>exam</code>, <code>examSet</code>, <code>evaluate</code>, <code>syntheticCriteria</code>, <code>exceprt</code></td></tr><tr><td><strong>Kế toán</strong></td><td><code>invoice</code>, <code>dealerDiscount</code></td></tr><tr><td><strong>Marketing</strong></td><td><code>menu</code>, <code>banner</code> (banner = nhóm Banner), <code>footer</code></td></tr></tbody></table><h2 id="phan-biet-nhan-vien-vs-giao-vien" tabindex="-1">Phân biệt Nhân viên vs Giáo viên <a class="header-anchor" href="#phan-biet-nhan-vien-vs-giao-vien" aria-label="Permalink to “Phân biệt Nhân viên vs Giáo viên”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Nhân viên</th><th>Giáo viên</th></tr></thead><tbody><tr><td>Khu vực làm việc</td><td><code>https://lamsonedutech.vn/admin/...</code></td><td><code>https://lamsonedutech.vn/teacher/...</code></td></tr><tr><td>Hiển thị trên trang khóa học</td><td>Không</td><td>Có (mặt giáo viên + bio)</td></tr><tr><td>Quản lý lớp học</td><td>Không</td><td>Có</td></tr><tr><td>Quản lý khóa do mình tạo</td><td>Tùy quyền</td><td>Có</td></tr><tr><td>Có thể tham gia ăn chia doanh thu</td><td>Không trực tiếp</td><td>Có (qua chiết khấu)</td></tr></tbody></table><p>→ Khi tạo tài khoản, chọn đúng loại để không lẫn quyền.</p>',19)])])}const v=t(e,[["render",o]]);export{m as __pageData,v as default};
